#include <stdio.h>

struct Proizvod {
    char naziv[20];
    float cijena;
};

void sortirajPoCijeni(struct Proizvod *p, int n) {
    for (int i = 0; i < n - 1; i++) {
        int minIndex = i;

        for (int j = i + 1; j < n; j++) {
            if ((p + j)->cijena < (p + minIndex)->cijena) {
                minIndex = j;
            }
        }

        if (minIndex != i) {
            struct Proizvod temp = *(p + i);
            *(p + i) = *(p + minIndex);
            *(p + minIndex) = temp;
        }
    }
}

int main() {
    struct Proizvod proizvodi[4] = {
        {"Hljeb", 2.0},
        {"Mlijeko", 2.5},
        {"Sir", 5.0},
        {"Jaja", 3.0}
    };

    int n = 4;
    struct Proizvod *p = proizvodi;

    sortirajPoCijeni(p, n);

    printf("Proizvodi sortirani po cijeni:\n");
    for (int i = 0; i < n; i++) {
        printf("%s - %.2f\n", (p + i)->naziv, (p + i)->cijena);
    }

    return 0;
}
